            sum_val += L[i, j] * x[j, tl.arange(0, BLOCK_SIZE)]
        x[i, tl.arange(0, BLOCK_SIZE)] = (b[i, tl.arange(0, BLOCK_SIZE)] - sum_val) / L[i, i]

